    void* output_buf;
    if (out_type_ == DT_QINT8) {
      output_buf = static_cast<void*>(
          const_cast<qint8*>(output->flat<qint8>().data()));
    } else {
      output_buf = static_cast<void*>(
          const_cast<quint8*>(output->flat<quint8>().data()));
